#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int i;
        float f;
        scanf("%d %f", &i, &f);
        printf("%d\n%.1f", i, f);
        if (T) printf("\n");
    }
    return 0;
}

